# Parent class 1
class Writer:
    def write(self):
        return "Writing content..."

# Parent class 2
class Editor:
    def edit(self):
        return "Editing content..."

# Child class inheriting from multiple parents
class ContentCreator(Writer, Editor):
    def create(self):
        return "Creating original content..."

    def process(self):
        # Call methods from both parents
        content = self.create()
        written = self.write()
        edited = self.edit()
        return f"{content} -> {written} -> {edited}"

# Demonstrate MRO
creator = ContentCreator()
print(creator.process())
print("\nMethod Resolution Order:")
for cls in ContentCreator.__mro__:
    print(f"  - {cls.__name__}")

# Diamond problem demonstration
class A:
    def greet(self):
        return "Hello from A"

class B(A):
    def greet(self):
        return "Hello from B"

class C(A):
    def greet(self):
        return "Hello from C"

class D(B, C):  # MRO: D -> B -> C -> A
    pass

d = D()
print(f"\nDiamond problem - D.greet(): {d.greet()}")
